const i = $input.first().json;
const t = i.tenant || {};
if (!t.business_id) throw new Error('Missing tenant.business_id');
const USD_TO_EGP = 49;
const pricing = {
  'anthropic/claude-haiku-4.5':  { input: 1.00,  output: 5.00 },
  'anthropic/claude-sonnet-4.5': { input: 3.00,  output: 15.00 },
  'anthropic/claude-opus-4.7':   { input: 15.00, output: 75.00 },
  'openai/gpt-4o':               { input: 2.50,  output: 10.00 },
  'openai/gpt-4o-mini':          { input: 0.15,  output: 0.60 },
  'google/gemini-2.0-flash':     { input: 0.10,  output: 0.40 }
};
const model = i.model || 'anthropic/claude-sonnet-4.5';
const inTok = parseInt(i.input_tokens || 0);
const outTok = parseInt(i.output_tokens || 0);
const mp = pricing[model] || pricing['anthropic/claude-sonnet-4.5'];
const costUsd = ((inTok * mp.input) + (outTok * mp.output)) / 1000000;
const costEgp = +(costUsd * USD_TO_EGP).toFixed(4);
return { json: {
  business_id: t.business_id,
  business_name: t.business_name || '',
  model, input_tokens: inTok, output_tokens: outTok,
  cost_usd: +costUsd.toFixed(6), cost_egp: costEgp,
  usage_body: { b_id: t.business_id, in_tokens: inTok, out_tokens: outTok, msg_cost: costEgp }
} };

const calc = $('CALCULATE_COST').first().json;
let row = $json;
if (Array.isArray(row)) row = row[0] || {};
const used = parseInt(row.messages_used ?? 0);
const limit = parseInt(row.message_limit ?? 0);
const remaining = Math.max(0, limit - used);
const exceeded = limit > 0 && used > limit;
return { json: {
  success: true,
  cost_egp: calc.cost_egp,
  cost_usd: calc.cost_usd,
  model: calc.model,
  messages_used: used,
  message_limit: limit,
  messages_remaining: remaining,
  limit_exceeded: exceeded,
  action: exceeded ? 'fallback_model' : 'allow',
  message: exceeded
    ? `تجاوزت الحد الشهري (${limit} رسالة). تواصل مع ${calc.business_name} للترقية.`
    : 'تم تحديث الاستهلاك بنجاح'
} };
